import React, { useState } from 'react'
import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import "../Css2/Navbar2.css"
export const Navbar = () => {
    let [active_nav,setActive_nav]=useState(false);
    const location=useLocation();
    useEffect(()=>{
        setActive_nav(false)
    },[location.hash])
    return (
        <div className='navbar'>
          <div className="navwraper">
          <div className='nav-left'>
                <img src="/Images/more.png" alt="hamberg" onClick={()=>{
                    setActive_nav(true)
                }} />
                <h3>@Ajaya</h3>
            </div>
            <div className={`nav-right ${active_nav?"active_nav":""}`}>
                <ul>
                    <li>
                        <a href="#Home">Home</a>
                    </li>
                    <li>
                        <a href="#Aboutme">AboutMe</a>
                    </li>
                    <li>
                        <a href="#Project">Project</a>
                    </li>
                    <li>
                        <a href="#Skill">Skill</a>
                    </li>
                    <li>
                        <a href="#Contact">Contact</a>
                    </li>
                    <li>
                        <a download href="/Project/Ajaya-Kumar-Behera-Resume.pdf">Resume</a>
                    </li>
                </ul>
                <img src="/Images/close.png" alt="close" onClick={()=>{
                    setActive_nav(false)
                }}/>
            </div>
          </div>
        </div>
    )
}
